#!/usr/bin/env python3
"""direction3-q-axis-ablation.py

Direction #3 Q-axis surfacing experiment for the standing-wave-mesh
theory. Tests whether ablating q_proj rows surfaces a coherent
intentional-pointer / interrogative vocab attractor, matching the
prediction Q = K XOR V from the Fano line embedding.

Method:
  1. Load Qwen2.5-0.5B (the same model from Section 7's K-axis result).
  2. Run baseline greedy decode on three prompts to capture the
     "correct" vocab distribution.
  3. Ablate the q_proj weight matrix of all attention layers (zero
     all rows). Re-run greedy decode on the same prompts.
  4. Decode the wrong tokens and compute their overlap with two
     candidate vocab classes:
        (a) interrogative / pointer (predicted Q-axis): what, which,
            where, who, when, why, how, ?, this, that, these, those
        (b) negation / exclusion (K-axis from Section 7): not, no,
            never, exclude, deny, refuse, 不, 没, 无
  5. Report counts. If wrong-token vocab clusters on (a) >> (b), the
     Fano XOR Q = K XOR V prediction survives. If on (b), the
     experiment is contaminated by K-axis leakage. If on neither, the
     prediction is weakened.

Output: a JSON report at the same dir plus stdout summary.

Run:
  cd open-source/gnosis/distributed-inference
  python3 direction3-q-axis-ablation.py
"""
import json
import sys
import time
from pathlib import Path

import os
os.environ.setdefault("KMP_DUPLICATE_LIB_OK", "TRUE")
os.environ.setdefault("OMP_NUM_THREADS", "1")
os.environ.setdefault("TOKENIZERS_PARALLELISM", "false")

import torch
from transformers import AutoModelForCausalLM, AutoTokenizer

MODEL = "Qwen/Qwen2.5-0.5B"
PROMPTS = [
    "The capital of France is",
    "Two plus two equals",
    "The opposite of hot is",
]
MAX_NEW_TOKENS = 16

# Vocab predictions for the two axes.
Q_AXIS_INTERROGATIVE = [
    " what", " which", " where", " who", " when", " why", " how",
    "?", " this", " that", " these", " those", " whose", " whom",
    " whether", " if", " ask", " query",
]
K_AXIS_NEGATION = [
    " not", " no", " never", " exclude", " deny", " refuse",
    " without", " cannot", " neither", " nor", "不", "没", "无",
    " forbidden", " illegal", " disallow",
]
V_AXIS_CONSTRUCTION = [
    " reestablish", " differentiation", " theoretical", " theorem",
    " construct", " establish", " definition", " distinction",
    " categorize", " classify", " formalize", " axiom",
]


def encode_class_token_ids(tokenizer, class_words):
    """Map each candidate word to its first token id; use a set for fast lookup."""
    ids = set()
    for word in class_words:
        encoded = tokenizer.encode(word, add_special_tokens=False)
        if encoded:
            ids.add(encoded[0])
    return ids


def greedy_decode(model, tokenizer, prompt, max_new_tokens=MAX_NEW_TOKENS):
    """Plain greedy decode; returns the list of generated token IDs and decoded text."""
    inputs = tokenizer(prompt, return_tensors="pt")
    input_ids = inputs.input_ids
    generated_ids = []

    with torch.no_grad():
        for _ in range(max_new_tokens):
            outputs = model(input_ids)
            next_logits = outputs.logits[:, -1, :]
            next_id = int(torch.argmax(next_logits, dim=-1).item())
            generated_ids.append(next_id)
            input_ids = torch.cat(
                [input_ids, torch.tensor([[next_id]], dtype=input_ids.dtype)],
                dim=-1,
            )
            if next_id == tokenizer.eos_token_id:
                break

    text = tokenizer.decode(generated_ids, skip_special_tokens=True)
    return generated_ids, text


def ablate_q_proj(model):
    """Zero out the q_proj weight matrix in every attention layer.
    Returns the originals for restoration."""
    originals = {}
    for name, module in model.named_modules():
        if name.endswith(".q_proj") and hasattr(module, "weight"):
            originals[name] = module.weight.data.clone()
            module.weight.data.zero_()
    return originals


def restore_q_proj(model, originals):
    for name, module in model.named_modules():
        if name in originals:
            module.weight.data.copy_(originals[name])


def class_membership(token_ids, class_token_ids):
    return sum(1 for t in token_ids if t in class_token_ids)


def main():
    print(f"[direction3] loading {MODEL}", flush=True)
    t0 = time.time()
    tokenizer = AutoTokenizer.from_pretrained(MODEL)
    model = AutoModelForCausalLM.from_pretrained(
        MODEL, torch_dtype=torch.float32, low_cpu_mem_usage=True
    )
    model.eval()
    print(f"[direction3] loaded in {time.time()-t0:.1f}s", flush=True)

    q_ids = encode_class_token_ids(tokenizer, Q_AXIS_INTERROGATIVE)
    k_ids = encode_class_token_ids(tokenizer, K_AXIS_NEGATION)
    v_ids = encode_class_token_ids(tokenizer, V_AXIS_CONSTRUCTION)
    print(f"[direction3] Q vocab ids: {len(q_ids)}; K vocab ids: {len(k_ids)}; V vocab ids: {len(v_ids)}", flush=True)

    results = {
        "model": MODEL,
        "max_new_tokens": MAX_NEW_TOKENS,
        "q_axis_vocab_size": len(q_ids),
        "k_axis_vocab_size": len(k_ids),
        "v_axis_vocab_size": len(v_ids),
        "baseline": [],
        "q_ablated": [],
    }

    print("\n=== BASELINE (no ablation) ===", flush=True)
    for prompt in PROMPTS:
        ids, text = greedy_decode(model, tokenizer, prompt)
        q_hits = class_membership(ids, q_ids)
        k_hits = class_membership(ids, k_ids)
        v_hits = class_membership(ids, v_ids)
        entry = {
            "prompt": prompt,
            "generated_ids": ids,
            "generated_text": text,
            "q_axis_hits": q_hits,
            "k_axis_hits": k_hits,
            "v_axis_hits": v_hits,
        }
        results["baseline"].append(entry)
        print(f"[baseline] {prompt!r:60s} -> {text!r}  Q={q_hits} K={k_hits} V={v_hits}", flush=True)

    print("\n=== Q-PROJ ABLATED (zero all q_proj weights) ===", flush=True)
    originals = ablate_q_proj(model)
    print(f"[direction3] zeroed {len(originals)} q_proj matrices", flush=True)
    for prompt in PROMPTS:
        ids, text = greedy_decode(model, tokenizer, prompt)
        q_hits = class_membership(ids, q_ids)
        k_hits = class_membership(ids, k_ids)
        v_hits = class_membership(ids, v_ids)
        entry = {
            "prompt": prompt,
            "generated_ids": ids,
            "generated_text": text,
            "q_axis_hits": q_hits,
            "k_axis_hits": k_hits,
            "v_axis_hits": v_hits,
        }
        results["q_ablated"].append(entry)
        print(f"[q-ablated] {prompt!r:60s} -> {text!r}  Q={q_hits} K={k_hits} V={v_hits}", flush=True)

    restore_q_proj(model, originals)

    base_q = sum(e["q_axis_hits"] for e in results["baseline"])
    base_k = sum(e["k_axis_hits"] for e in results["baseline"])
    base_v = sum(e["v_axis_hits"] for e in results["baseline"])
    abl_q = sum(e["q_axis_hits"] for e in results["q_ablated"])
    abl_k = sum(e["k_axis_hits"] for e in results["q_ablated"])
    abl_v = sum(e["v_axis_hits"] for e in results["q_ablated"])
    total_tokens = MAX_NEW_TOKENS * len(PROMPTS)

    summary = {
        "total_generated_tokens": total_tokens,
        "baseline_q_axis_pct": round(100 * base_q / total_tokens, 2),
        "baseline_k_axis_pct": round(100 * base_k / total_tokens, 2),
        "baseline_v_axis_pct": round(100 * base_v / total_tokens, 2),
        "ablated_q_axis_pct": round(100 * abl_q / total_tokens, 2),
        "ablated_k_axis_pct": round(100 * abl_k / total_tokens, 2),
        "ablated_v_axis_pct": round(100 * abl_v / total_tokens, 2),
        "q_axis_surfaced": abl_q > base_q and abl_q > abl_k,
        "k_axis_leak": abl_k > abl_q,
        "neither_axis_dominates": abl_q == 0 and abl_k == 0 and abl_v == 0,
    }
    results["summary"] = summary

    out_path = Path(__file__).parent / "direction3-q-axis-ablation-results.json"
    out_path.write_text(json.dumps(results, indent=2))
    print(f"\n[direction3] wrote results to {out_path}", flush=True)

    print("\n=== SUMMARY ===", flush=True)
    print(f"total tokens generated: {total_tokens}", flush=True)
    print(f"  baseline:  Q={summary['baseline_q_axis_pct']:5.2f}%  K={summary['baseline_k_axis_pct']:5.2f}%  V={summary['baseline_v_axis_pct']:5.2f}%", flush=True)
    print(f"  q-ablated: Q={summary['ablated_q_axis_pct']:5.2f}%  K={summary['ablated_k_axis_pct']:5.2f}%  V={summary['ablated_v_axis_pct']:5.2f}%", flush=True)
    print(f"  q_axis_surfaced: {summary['q_axis_surfaced']}", flush=True)
    print(f"  k_axis_leak:     {summary['k_axis_leak']}", flush=True)
    print(f"  neither_axis_dominates: {summary['neither_axis_dominates']}", flush=True)

    if summary["q_axis_surfaced"]:
        print("\n  VERDICT: Q-axis prediction SURVIVED — interrogative vocab surfaced under q_proj ablation.", flush=True)
    elif summary["k_axis_leak"]:
        print("\n  VERDICT: K-axis LEAKED — ablation collapsed to negation axis, not Q.", flush=True)
    else:
        print("\n  VERDICT: Q-axis prediction WEAKENED — no clear vocab class dominated.", flush=True)

    return 0


if __name__ == "__main__":
    sys.exit(main())
